// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	var showSubCategory=false;

	// STRY0130088 
	if(isLoading){
		showSubCategory = g_scratchpad.subCategoryCount>0;
		if(g_form.getControl('sub_category')){
			g_form.setDisplay('sub_category', showSubCategory);
			g_form.setDisabled('sub_category', !showSubCategory);
		}
		return;
	}
	// evaluate this on load and on change
	// NOTE: This was in a UI Policy, but the policy was causing the form UI Actions to fail for portal.
	//       So, moved into onChnage and also running on load.
	var categoryId = g_form.getValue('category') +'';
	// if the control isn't on the form, don't call back to the server
	if (g_form.getControl('sub_category')){
		if(newValue!=oldValue){
			g_form.setValue('sub_category',"");
		}
		if(categoryId != ''){
			var ajax  = new GlideAjax('ClientTaskInfo');
			ajax.addParam('sysparm_name', 'getSubCategoryCount');
			ajax.addParam('sysparm_categoryId', categoryId);
			ajax.getXML(f_return_activateSubCategory);
		} else {
			g_form.setDisplay('sub_category', false);
			g_form.setDisabled('sub_category', true);	
		}
	}

	function f_return_activateSubCategory(response){
		try{
			// STRY0130088 
			var subCategoryCount = 0;
			var answer = response.responseXML.documentElement.getAttribute("answer");
			subCategoryCount = parseInt(answer);
			showSubCategory = subCategoryCount>0;
			g_form.setDisplay('sub_category', showSubCategory);
			g_form.setDisabled('sub_category', !showSubCategory);
		}catch(e){
			jslog(e);
		}	
	}
}
